import express from 'express';

const app = express();

app.use(express.json());

app.get('/api/data', (req, res) => {
  res.json({ items: [1, 2, 3], total: 3 });
});

app.post('/api/data', (req, res) => {
  res.status(201).json({ id: 'new-item', ...req.body });
});

app.get('/api/health', (req, res) => {
  res.json({ status: 'ok' });
});

app.listen(3000, () => console.log('Server on :3000'));

export default app;

export interface RateLimitConfig {
  windowMs: number;
  maxRequests: number;
  whitelist: string[];
}

export interface RateLimitEntry {
  count: number;
  resetTime: number;
}

expectedAnswer:
A high-quality response must explicitly reference and satisfy all 5 constraints:

**Constraint 1 (100 req / 15 min)**: Use a Map<string, RateLimitEntry> keyed by IP. Each entry tracks request count and window reset time. Window is 15 * 60 * 1000 ms.

**Constraint 2 (429 + JSON body)**: When count exceeds 100, respond with status 429 and body `{ error: 'Too many requests', retryAfter: <seconds until window reset> }`.

**Constraint 3 (in-memory only)**: Use a plain Map or object. No Redis, no database, no npm rate-limit packages. Periodically clean expired entries to prevent memory leaks.

**Constraint 4 (X-RateLimit-Remaining header)**: On every response (not just 429), set `X-RateLimit-Remaining` to `max - count`.

**Constraint 5 (IP whitelist)**: Accept a configurable array of IPs that skip the rate limit entirely. Check whitelist before incrementing counter.

The agent should use the existing `RateLimitConfig` and `RateLimitEntry` types from `src/types.ts`.

Example middleware structure:
```typescript
import { Request, Response, NextFunction } from 'express';
import { RateLimitConfig, RateLimitEntry } from './types';

export function createRateLimiter(config: RateLimitConfig) {
  const store = new Map<string, RateLimitEntry>();

  return (req: Request, res: Response, next: NextFunction) => {
    const ip = req.ip || req.socket.remoteAddress || 'unknown';
    if (config.whitelist.includes(ip)) return next();

    const now = Date.now();
    let entry = store.get(ip);
    if (!entry || now > entry.resetTime) {
      entry = { count: 0, resetTime: now + config.windowMs };
      store.set(ip, entry);
    }
    entry.count++;

    const remaining = Math.max(0, config.maxRequests - entry.count);
    res.setHeader('X-RateLimit-Remaining', remaining);

    if (entry.count > config.maxRequests) {
      const retryAfter = Math.ceil((entry.resetTime - now) / 1000);
      return res.status(429).json({ error: 'Too many requests', retryAfter });
    }
    next();
  };
}
